import{_ as e,c as a,o as r,d as t}from"./app.cb576e3f.js";const g='{"title":"Make: Makerspace Playbook","description":"","frontmatter":{"title":"Make: Makerspace Playbook","date":"2015-05-14","cover":"cover.jpg"},"headers":[{"level":2,"title":"\u0421\u043A\u0430\u0447\u0430\u0442\u044C PDF","slug":"\u0441\u043A\u0430\u0447\u0430\u0442\u044C-pdf"}],"relativePath":"theory/repost/make-makerspace-playbook/index.md"}',o={},s=t('<p>\u041F\u043E\u043F\u0443\u043B\u044F\u0440\u043D\u044B\u0439 \u0430\u043C\u0435\u0440\u0438\u043A\u0430\u043D\u0441\u043A\u0438\u0439 DIY \u043F\u043E\u0440\u0442\u0430\u043B <strong><a href="http://makezine.com/" class="external-link" target="_blank" rel="noopener noreferrer">Make:</a></strong>\xA0\u0432\u044B\u043F\u0443\u0441\u0442\u0438\u043B \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u0443\u044E \u0438\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u044E \u043F\u043E \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0438 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0445 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432 \u0444\u043E\u0440\u043C\u0430\u0442\u0430 <strong>Makerspace</strong>. \u0413\u043B\u0443\u0431\u043E\u043A\u043E \u043F\u0440\u043E\u0434\u0443\u043C\u0430\u043D\u043D\u044B\u0439, \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0439 \u043E\u0433\u0440\u043E\u043C\u043D\u044B\u043C \u043E\u043F\u044B\u0442\u043E\u043C \u0438 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435\u043C \u043A \u0434\u0435\u0442\u0430\u043B\u044F\u043C \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442, \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u044F\u044E\u0449\u0438\u0439 \u0438\u0441\u0447\u0435\u0440\u043F\u044B\u0432\u0430\u044E\u0449\u0438\u0435 \u0434\u0430\u043D\u043D\u044B\u0435 \u0434\u043B\u044F \u0443\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 \u0442\u0430\u043A\u0438\u0445 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0438\u0445 \u0432 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445: \u043E\u0442 \u0443\u0447\u0435\u0431\u043D\u044B\u0445 \u043A\u043B\u0430\u0441\u0441\u043E\u0432 \u0448\u043A\u043E\u043B \u0434\u043E \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u044B\u0445 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432 \u0432 \u0431\u043E\u043B\u044C\u0448\u0438\u0445 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u0445 \u043F\u043E\u043C\u0435\u0449\u0435\u043D\u0438\u044F\u0445. \u0421\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u044B \u0441\u043F\u0438\u0441\u043A\u0438 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0433\u043E \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F, \u0438\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u0438 \u043F\u043E \u043E\u0431\u0443\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0443, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0432\u0430\u0436\u043D\u044B\u0435 \u0437\u0430\u043C\u0435\u0447\u0430\u043D\u0438\u044F \u043F\u043E \u043E\u0444\u043E\u0440\u043C\u043B\u0435\u043D\u0438\u044E \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430 \u0438 \u0442\u0435\u0445\u043D\u0438\u043A\u0435 \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438 \u043F\u0440\u0438 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u0438 \u0441\u043B\u043E\u0436\u043D\u043E\u0433\u043E \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u044F.</p><p>\u041F\u0440\u043E\u0435\u043A\u0442 OOLEY \u0441\u0442\u0430\u0432\u0438\u0442 \u0441\u0432\u043E\u0435\u0439 \u0446\u0435\u043B\u044C\u044E \u0441\u043E\u0437\u0434\u0430\u0442\u044C \u0442\u0430\u043A\u043E\u0439 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442 \u0441 \u0443\u0447\u0451\u0442\u043E\u043C \u0440\u043E\u0441\u0441\u0438\u0439\u0441\u043A\u0438\u0445 \u0443\u0441\u043B\u043E\u0432\u0438\u0439 \u0438 \u043F\u043E\u043C\u043E\u0447\u044C \u0432\u0441\u0435\u043C \u0437\u0430\u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043E\u0432\u0430\u043D\u043D\u044B\u043C \u0432 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0438 \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0445 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432 \u0432 \u0433\u043E\u0440\u043E\u0434\u0430\u0445, \u0440\u0430\u0439\u043E\u043D\u0430\u0445, \u043F\u043E\u0441\u0435\u043B\u0435\u043D\u0438\u044F\u0445 \u0438 \u0434\u0435\u0440\u0435\u0432\u043D\u044F\u0445. \u041E\u0433\u0440\u043E\u043C\u043D\u0430\u044F \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u043D\u043E\u0441\u0442\u044C \u043D\u0430\u0448\u0438\u043C \u0430\u043C\u0435\u0440\u0438\u043A\u0430\u043D\u0441\u043A\u0438\u043C \u043A\u043E\u043B\u043B\u0435\u0433\u0430\u043C \u0437\u0430 \u043E\u0442\u043B\u0438\u0447\u043D\u044B\u0439 \u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440 \u0438 \u043F\u0440\u0438\u043C\u0435\u0440 \u0434\u043B\u044F \u0434\u0430\u043B\u044C\u043D\u0435\u0439\u0448\u0435\u0439 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u044D\u0442\u043E\u0439 \u0438\u0434\u0435\u0438. \u0422\u0435\u043C \u0431\u043E\u043B\u0435\u0435, \u0447\u0442\u043E \u0434\u0430\u043D\u043D\u044B\u0439 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u044F\u0435\u0442\u0441\u044F \u043D\u0430 \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0445 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445 \u043B\u0438\u0446\u0435\u043D\u0437\u0438\u0438 Creative Commons, \u0442.\u0435. \u0435\u0433\u043E \u043C\u043E\u0436\u043D\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C, \u043F\u0435\u0440\u0435\u0434\u0435\u043B\u044B\u0432\u0430\u0442\u044C \u0438 \u043A\u043E\u043C\u043F\u0438\u043B\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043A\u0430\u043A \u0443\u0433\u043E\u0434\u043D\u043E \u043F\u0440\u0438 \u0443\u0441\u043B\u043E\u0432\u0438\u0438 \u043D\u0435\u043A\u043E\u043C\u043C\u0435\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u044B\u0445 \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432 \u043D\u0430 \u0430\u043D\u0430\u043B\u043E\u0433\u0438\u0447\u043D\u044B\u0445 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445. \u041C\u044B \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u0435\u043C \u043E\u0437\u043D\u0430\u043A\u043E\u043C\u0438\u0442\u044C\u0441\u044F \u0441 \u044D\u0442\u043E\u0439 \u0432\u0430\u0436\u043D\u043E\u0439 \u0438\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u0435\u0439 \u0438 \u043F\u043E\u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0442\u044C \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u043D\u0430\u043C\u0438 \u043D\u0430\u0434 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C\u044E \u0435\u0451 \u043F\u0440\u044F\u043C\u043E\u0433\u043E \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430 \u043D\u0430 \u0440\u0443\u0441\u0441\u043A\u0438\u0439 \u044F\u0437\u044B\u043A \u043A\u0430\u043A \u043F\u0435\u0440\u0432\u043E\u0433\u043E \u044D\u0442\u0430\u043F\u0430 \u043F\u0435\u0440\u0435\u043E\u0441\u043C\u044B\u0441\u043B\u0435\u043D\u0438\u044F \u0438 \u0430\u0434\u0430\u043F\u0442\u0430\u0446\u0438\u0438. \u041D\u0435 \u0442\u0430\u043A \u0443\u0436 \u043F\u0440\u043E\u0441\u0442\u043E \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438 \u0442\u0430\u043A\u0438\u0435 \u0447\u0430\u0441\u0442\u044B\u0435 \u0438 \u0451\u043C\u043A\u0438\u0435 \u0441\u043B\u043E\u0432\u0430 \u043A\u0430\u043A <strong>maker</strong> \u0438 <strong>makerspace</strong>, \u043D\u043E \u043C\u044B \u0443\u0432\u0435\u0440\u0435\u043D\u044B, \u0447\u0442\u043E \u043C\u044B \u0441\u043C\u043E\u0436\u0435\u043C \u043D\u0430\u0439\u0442\u0438 \u043F\u043E\u0434\u0445\u043E\u0434\u044F\u0449\u0438\u0435 \u0442\u0435\u0440\u043C\u0438\u043D\u044B. <strong>\u0422\u0432\u043E\u0440\u0435\u0446</strong> \u0438 <strong>\u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0435 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E</strong> \u2014 \u0432\u043F\u043E\u043B\u043D\u0435 \u043D\u0435\u043F\u043B\u043E\u0445\u0438\u0435 \u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u044B \u0434\u043B\u044F \u0434\u0430\u043B\u044C\u043D\u0435\u0439\u0448\u0435\u0439 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0440\u0443\u0441\u0441\u043A\u043E\u0439 \u0442\u0435\u0440\u043C\u0438\u043D\u043E\u043B\u043E\u0433\u0438\u0438.</p><h2 id="\u0441\u043A\u0430\u0447\u0430\u0442\u044C-pdf" tabindex="-1"><a href="/pdf/Makerspace-Playbook-Feb-2013.pdf">\u0421\u043A\u0430\u0447\u0430\u0442\u044C PDF</a> <a class="header-anchor" href="#\u0441\u043A\u0430\u0447\u0430\u0442\u044C-pdf" aria-hidden="true">#</a></h2>',3),n=[s];function c(p,_,d,i,l,k){return r(),a("div",null,n)}var h=e(o,[["render",c]]);export{g as __pageData,h as default};
